## 1. Type Definitions (from `tui.d.ts`)

```typescript
export type OverlayAnchor = "center" | "top-left" | "top-right" | "bottom-left" | "bottom-right" | "top-center" | "bottom-center" | "left-center" | "right-center";

export interface OverlayMargin { top?: number; right?: number; bottom?: number; left?: number; }

export type SizeValue = number | `${number}%`;

export interface OverlayOptions {
    width?: SizeValue;
    minWidth?: number;
    maxHeight?: SizeValue;
    anchor?: OverlayAnchor;        // default: 'center'
    offsetX?: number;              // horizontal offset from anchor (positive=right)
    offsetY?: number;              // vertical offset from anchor (positive=down)
    row?: SizeValue;               // absolute row or "% from top"
    col?: SizeValue;               // absolute col or "% from left"
    margin?: OverlayMargin | number;
    visible?: (termWidth: number, termHeight: number) => boolean;
    nonCapturing?: boolean;
}

export interface OverlayHandle {
    hide(): void;
    setHidden(hidden: boolean): void;
    isHidden(): boolean;
    focus(): void;
    unfocus(options?: OverlayUnfocusOptions): void;
    isFocused(): boolean;
}
```

