## 2. `resolveOverlayLayout()` (line 594)

```js
resolveOverlayLayout(options, overlayHeight, termWidth, termHeight) {
    const opt = options ?? {};
    const margin = typeof opt.margin === "number"
        ? { top: opt.margin, right: opt.margin, bottom: opt.margin, left: opt.margin }
        : (opt.margin ?? {});
    const marginTop = Math.max(0, margin.top ?? 0);
    const marginRight = Math.max(0, margin.right ?? 0);
    const marginBottom = Math.max(0, margin.bottom ?? 0);
    const marginLeft = Math.max(0, margin.left ?? 0);
    const availWidth = Math.max(1, termWidth - marginLeft - marginRight);
    const availHeight = Math.max(1, termHeight - marginTop - marginBottom);

    // === Resolve width ===
    let width = parseSizeValue(opt.width, termWidth) ?? Math.min(80, availWidth);
    if (opt.minWidth !== undefined) width = Math.max(width, opt.minWidth);
    width = Math.max(1, Math.min(width, availWidth));

    // === Resolve maxHeight ===
    let maxHeight = parseSizeValue(opt.maxHeight, termHeight);
    if (maxHeight !== undefined) maxHeight = Math.max(1, Math.min(maxHeight, availHeight));
    const effectiveHeight = maxHeight !== undefined ? Math.min(overlayHeight, maxHeight) : overlayHeight;

    // === Resolve position ===
    let row, col;
    if (opt.row !== undefined) {
        if (typeof opt.row === "string") {
            const match = opt.row.match(/^(\d+(?:\.\d+)?)%$/);
            if (match) {
                const maxRow = Math.max(0, availHeight - effectiveHeight);
                const percent = parseFloat(match[1]) / 100;
                row = marginTop + Math.floor(maxRow * percent);
            } else {
                row = this.resolveAnchorRow("center", effectiveHeight, availHeight, marginTop);
            }
        } else {
            row = opt.row;  // absolute row
        }
    } else {
        const anchor = opt.anchor ?? "center";
        row = this.resolveAnchorRow(anchor, effectiveHeight, availHeight, marginTop);
    }
    // col resolved similarly...

    if (opt.offsetY !== undefined) row += opt.offsetY;
    if (opt.offsetX !== undefined) col += opt.offsetX;

    // Clamp to terminal bounds (respecting margins)
    row = Math.max(marginTop, Math.min(row, termHeight - marginBottom - effectiveHeight));
    col = Math.max(marginLeft, Math.min(col, termWidth - marginRight - width));
    return { width, row, col, maxHeight };
}
```

**Key:** `row` is resolved against `availHeight` (derived from `termHeight`), **not** content height. The final clamp uses `termHeight`.

