## 3. `showOverlay()` (line 269)

```js
showOverlay(component, options) {
    const entry = {
        component,
        ...(options === undefined ? {} : { options }),
        preFocus: this.focusedComponent,
        hidden: false,
        focusOrder: ++this.focusOrderCounter,
    };
    this.overlayStack.push(entry);
    if (!options?.nonCapturing && this.isOverlayVisible(entry)) {
        this.setFocus(component);
    }
    this.terminal.hideCursor();
    this.requestRender();
    return {
        hide: () => { /* splice from stack, restore focus, requestRender */ },
        setHidden: (hidden) => { /* toggle entry.hidden, manage focus */ },
        isHidden: () => entry.hidden,
        focus: () => { /* bring to front, setFocus */ },
        unfocus: (unfocusOptions) => { /* release focus to next overlay or preFocus */ },
        isFocused: () => this.focusedComponent === component,
    };
}
```

